boxes = input().split()
red_count = 0
white_count = 0
blue_count = 0

for box in boxes:
    if box == '0':
        red_count += 1
    elif box == '1':
        white_count += 1
    elif box == '2':
        blue_count += 1

sorted_boxes = ""
for i in range(red_count):
    sorted_boxes += "0 "
for j in range(white_count):
    sorted_boxes += "1 "
for k in range(blue_count):
    sorted_boxes += "2 "

sorted_boxes = sorted_boxes
print(sorted_boxes)
